import java.io.*;
import java.util.*;

public class Main{
    static class ShapeCalculator{
        static long calculateArea(long side){return side*side;}
        static long calculateArea(long length,long breadth){return length*breadth;}
    }
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        String line=br.readLine();
        if(line==null||line.isEmpty()) return;
        int T=Integer.parseInt(line.trim());
        StringBuilder sb=new StringBuilder();
        for(int t=0;t<T;t++){
            long s=Long.parseLong(br.readLine().trim());
            StringTokenizer st=new StringTokenizer(br.readLine());
            long l=Long.parseLong(st.nextToken());
            long b=Long.parseLong(st.nextToken());
            sb.append(ShapeCalculator.calculateArea(s)).append('\n');
            sb.append(ShapeCalculator.calculateArea(l,b)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

