const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
if(input.length===0) process.exit(0);
const T=Number(input[idx++]);
let out=[];
function calculateArea(a,b){
    if(b===undefined) return a*a;
    return a*b;
}
for(let t=0;t<T;t++){
    const s=Number(input[idx++]);
    const l=Number(input[idx++]);
    const b=Number(input[idx++]);
    out.push(String(calculateArea(s)));
    out.push(String(calculateArea(l,b)));
}
